class MPSuperTokenMetrics{PLATFORM_NAME="woocommerce";CORE_MONITOR_URL="https://api.mercadopago.com/ppcore/prod/monitor/v1/event/datadog/big";MELIDATA_ERROR_EVENT_NAME="mp_checkout_error";PLUGIN_VERSION=wc_mercadopago_supertoken_bundle_params.plugin_version;PLATFORM_VERSION=wc_mercadopago_supertoken_bundle_params.platform_version;SITE_ID=wc_mercadopago_supertoken_bundle_params.site_id;CUST_ID=wc_mercadopago_supertoken_bundle_params.cust_id;LOCATION=wc_mercadopago_supertoken_bundle_params.location;SUPER_TOKEN_JS_VERSION=null;CUSTOM_CHECKOUT_STEPS={LOAD_SUPER_TOKEN:"load_super_token",SELECT_PAYMENT_METHOD:"select_payment_method",POST_SUBMIT:"post_submit"};mpSdkInstance=null;constructor(e,t){this.mpSdkInstance=e,this.SUPER_TOKEN_JS_VERSION=t}getSdkInstanceId(){try{return this?.mpSdkInstance?.getSDKInstanceId()||"Unknown"}catch(e){return"Unknown"}}getEnvironment(){return"prod"}sendMetric(e,t,r){fetch(`${this.CORE_MONITOR_URL}/${e}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({value:`${t}`,message:`${r}`,plugin_version:this.PLUGIN_VERSION,platform:{name:this.PLATFORM_NAME,uri:window.location.href,version:this.PLATFORM_VERSION,url:`${this.LOCATION}${this.THEME?`_${this.THEME}`:""}`},details:{site_id:this.SITE_ID,environment:this.getEnvironment(),sdk_instance_id:this.getSdkInstanceId(),cust_id:this.CUST_ID,js_version:this.SUPER_TOKEN_JS_VERSION}})}).catch((e=>console.error("Super Token metrics error: ",e)))}dispatchMelidataErrorEvent(e,t){document.dispatchEvent(new CustomEvent(this.MELIDATA_ERROR_EVENT_NAME,{detail:{message:e,errorOrigin:t}}))}normalizeErrorMessage(e){if(!e)return"Unknown error";const t=e?.message||`${JSON.stringify(e)}`;return(t?.includes("email")?"invalid_email_address_provided":t)||"Unknown error"}canUseSuperToken(e,t=null){const r=this.normalizeErrorMessage(t);this.sendMetric("can_use_super_token",e,r)}errorToAuthorizePayment(e){const t=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(t,this.CUSTOM_CHECKOUT_STEPS.POST_SUBMIT),this.sendMetric("error_to_authorize_payment","true",t)}errorToGetSimplifiedAuth(e){const t=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(t,this.CUSTOM_CHECKOUT_STEPS.LOAD_SUPER_TOKEN),this.sendMetric("error_to_get_simplified_auth","true",t)}errorToGetFastPaymentToken(e){const t=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(t,this.CUSTOM_CHECKOUT_STEPS.LOAD_SUPER_TOKEN),this.sendMetric("error_to_get_fast_payment_token","true",t)}errorToBuildAuthenticator(e){const t=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(t,this.CUSTOM_CHECKOUT_STEPS.LOAD_SUPER_TOKEN),this.sendMetric("error_to_build_authenticator","true",t)}errorToMountCVVField(e,t){const r=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(r,this.CUSTOM_CHECKOUT_STEPS.SELECT_PAYMENT_METHOD),this.sendMetric("error_to_mount_cvv_field",t?.id||"Unknown payment method",r)}errorToUpdateSecurityCode(e,t){const r=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(r,this.CUSTOM_CHECKOUT_STEPS.POST_SUBMIT),this.sendMetric("error_to_update_security_code",t?.token||"Unknown payment method token",r)}errorOnSubmit(e,t){const r=this.normalizeErrorMessage(t);this.dispatchMelidataErrorEvent(r,this.CUSTOM_CHECKOUT_STEPS.POST_SUBMIT),this.sendMetric("error_on_submit_super_token",e,r)}errorToGetAccountPaymentMethods(e){const t=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(t,this.CUSTOM_CHECKOUT_STEPS.LOAD_SUPER_TOKEN),this.sendMetric("error_to_get_account_payment_methods","true",t)}registerClickOnPlaceOrderButton(){this.sendMetric("super_token_click_on_place_order_button","true","")}registerAuthorizedPseudotoken(e,t){this.sendMetric("authorized_pseudotoken",e,"input_exists:"+(t?"true":"false"))}errorToRenderAccountPaymentMethods(e){const t=this.normalizeErrorMessage(e);this.sendMetric("error_to_render_account_payment_methods","true",t)}isNotSimplifiedAuth(){this.sendMetric("is_not_simplified_auth","true","")}cannotGetFastPaymentToken(){this.sendMetric("cannot_get_fast_payment_token","true","")}}